try {
  const items = $input.all();
  const business = $node['Split In Batches'].json;
  let weeklyReach = 0, weeklyEngagement = 0, weeklyImpressions = 0;
  for (const item of items) {
    weeklyReach += item.json.reach || 0;
    weeklyEngagement += item.json.engagement || 0;
    weeklyImpressions += item.json.impressions || 0;
  }
  return [{
    json: {
      business_id: business.id,
      business_name: business.business_name || '',
      email: business.email || '',
      weekly_reach: weeklyReach,
      weekly_engagement: weeklyEngagement,
      weekly_impressions: weeklyImpressions,
      total_reach: business.total_reach || 0,
      industry: business.industry || 'business'
    }
  }];
} catch(e) {
  return [{json: {error: e.message, business_id: $node['Split In Batches'].json.id}}];
}

