try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    let parsed;
    try {
      const text = item.json.content[0].text;
      parsed = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      parsed = match ? JSON.parse(match[0]) : {linkedin_post: '', instagram_caption: '', twitter_post: '', hashtags: []};
    }
    results.push({json: {
      business_id: $node['Compile Weekly Stats'].json.business_id,
      business_name: $node['Compile Weekly Stats'].json.business_name,
      email: $node['Compile Weekly Stats'].json.email,
      weekly_reach: $node['Compile Weekly Stats'].json.weekly_reach,
      weekly_engagement: $node['Compile Weekly Stats'].json.weekly_engagement,
      linkedin_post: parsed.linkedin_post || '',
      instagram_caption: parsed.instagram_caption || '',
      twitter_post: parsed.twitter_post || '',
      hashtags: (parsed.hashtags || []).join(' ')
    }});
  }
  return results;
} catch(e) {
  return [{json: {error: e.message}}];
}
